/**
 * search.js — lightweight client-side search powered by searchindex.json.
 *
 * Fetches /searchindex.json (generated by Hugo's SearchIndex output format),
 * then filters pages by the user's query across title, description, tags,
 * categories, and content.
 *
 * Usage: include this script on any page that has a search form matching
 * the expected markup:
 *
 *   <form id="search-form" role="search">
 *     <input id="search-input" type="search" placeholder="Search…"
 *            aria-label="Search site content">
 *   </form>
 *   <div id="search-results" aria-live="polite"></div>
 */

(function () {
  "use strict";

  // Resolved once the index is fetched
  let indexData = null;

  const searchIndexURL = "/searchindex.json";

  /** Fetch and cache the search index. */
  async function loadIndex() {
    if (indexData) return indexData;
    try {
      const response = await fetch(searchIndexURL);
      if (!response.ok) throw new Error(`HTTP ${response.status}`);
      indexData = await response.json();
    } catch (err) {
      console.warn("[search] Could not load search index:", err);
      indexData = [];
    }
    return indexData;
  }

  /**
   * Search the index for pages matching all terms in `query`.
   * Returns an array of matching page objects, limited to `maxResults`.
   */
  function search(pages, query, maxResults = 20) {
    if (!query || !query.trim()) return [];

    const terms = query
      .toLowerCase()
      .split(/\s+/)
      .filter(Boolean);

    return pages
      .filter((page) => {
        const haystack = [
          page.title,
          page.description,
          (page.tags ?? []).join(" "),
          (page.categories ?? []).join(" "),
          page.content,
        ]
          .join(" ")
          .toLowerCase();

        return terms.every((term) => haystack.includes(term));
      })
      .slice(0, maxResults);
  }

  /** Build and return the results HTML string. */
  function renderResults(results, query) {
    if (!results.length) {
      return `<p class="text-gray-600 dark:text-gray-400">
        No results found for <strong>${escapeHtml(query)}</strong>.
      </p>`;
    }

    const items = results
      .map(
        (page) => `
      <article class="py-4 border-b border-gray-200 dark:border-gray-700 last:border-0">
        <a href="${escapeHtml(page.url)}"
           class="text-blue-600 dark:text-blue-400 font-semibold hover:underline focus:outline-none focus:ring-2 focus:ring-blue-500 rounded">
          ${escapeHtml(page.title)}
        </a>
        ${
          page.description
            ? `<p class="mt-1 text-sm text-gray-600 dark:text-gray-400">${escapeHtml(page.description)}</p>`
            : ""
        }
        <p class="mt-1 text-xs text-gray-500 dark:text-gray-500">${escapeHtml(page.url)}</p>
      </article>`
      )
      .join("");

    return `<p class="text-sm text-gray-600 dark:text-gray-400 mb-4">
      ${results.length} result${results.length === 1 ? "" : "s"} for
      <strong>${escapeHtml(query)}</strong>
    </p>
    <div role="list">${items}</div>`;
  }

  /** Minimal HTML-escape to avoid XSS in rendered results. */
  function escapeHtml(str) {
    return String(str)
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;");
  }

  /** Wire up the search form and results container once the DOM is ready. */
  function init() {
    const form = document.getElementById("search-form");
    const input = document.getElementById("search-input");
    const resultsEl = document.getElementById("search-results");

    if (!form || !input || !resultsEl) return;

    // Pre-fetch the index so the first search is fast
    loadIndex();

    let debounceTimer;

    input.addEventListener("input", () => {
      clearTimeout(debounceTimer);
      debounceTimer = setTimeout(async () => {
        const query = input.value.trim();

        if (!query) {
          resultsEl.innerHTML = "";
          return;
        }

        const pages = await loadIndex();
        const results = search(pages, query);
        resultsEl.innerHTML = renderResults(results, query);
      }, 250);
    });

    form.addEventListener("submit", (e) => {
      e.preventDefault();
    });
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", init);
  } else {
    init();
  }
})();
